import json, re

# Load package data (file path)
with open(locals()['var_functions.query_db:76'], 'r') as f:
    packages = json.load(f)

print(f'Loaded {len(packages)} package records')

# Step 1: Find latest release version for each package
latest_releases = {}
for pkg in packages:
    name = pkg['Name']
    version = pkg['Version']
    vi_str = pkg['VersionInfo']

    # Extract Ordinal and IsRelease
    ordinal_match = re.search(r'"Ordinal":\s*(\d+)', vi_str)
    release_match = re.search(r'"IsRelease":\s*(true|false)', vi_str)

    if ordinal_match and release_match:
        try:
            ordinal = int(ordinal_match.group(1))
            is_release = release_match.group(1) == 'true'

            if is_release:
                if name not in latest_releases or ordinal > latest_releases[name]['ordinal']:
                    latest_releases[name] = {
                        'version': version,
                        'ordinal': ordinal
                    }
        except:
            continue

print(f'Found {len(latest_releases)} latest release versions')

# Step 2: Get project mappings
mappings = locals()['var_functions.query_db:42']
if isinstance(mappings, str):
    with open(mappings, 'r') as f:
        mappings = json.load(f)

print(f'Loaded {len(mappings)} project mappings')

# Index mappings by package name and version
mapping_index = {}
for m in mappings:
    if m['System'] == 'NPM':
        key = (m['Name'], m['Version'])
        mapping_index[key] = m['ProjectName']

# Step 3: Match packages with projects
package_projects = []
for name, data in latest_releases.items():
    key = (name, data['version'])
    if key in mapping_index:
        package_projects.append({
            'package': name,
            'version': data['version'],
            'project': mapping_index[key]
        })

print(f'Matched {len(package_projects)} packages to GitHub projects')

# Step 4: Load project info and extract stars
proj_file = locals()['var_functions.query_db:70']
with open(proj_file, 'r') as f:
    project_infos = json.load(f)

print(f'Loaded {len(project_infos)} project info records')

# Extract star counts from project descriptions
project_stars = {}
for info in project_infos:
    text = info.get('Project_Information', '')
    star_match = re.search(r'(\d{1,3}(?:,\d{3})*(?:\+)?)\s+stars?', text, re.IGNORECASE)
    proj_match = re.search(r'project\s+([^/\s]+/[^/\s,]+)', text, re.IGNORECASE)

    if star_match and proj_match:
        try:
            stars = int(star_match.group(1).replace(',', '').replace('+', ''))
            project_name = proj_match.group(1)
            project_stars[project_name] = stars
        except:
            continue

print(f'Extracted star counts for {len(project_stars)} projects')

# Step 5: Combine everything and get top 5
results = []
for pkg in package_projects:
    if pkg['project'] in project_stars:
        results.append({
            'package': pkg['package'],
            'version': pkg['version'],
            'project': pkg['project'],
            'stars': project_stars[pkg['project']]
        })

# Sort by stars and get top 5
top_packages = sorted(results, key=lambda x: x['stars'], reverse=True)[:5]

print(f'Final results: {len(top_packages)} packages')
print('__RESULT__:')
print(json.dumps(top_packages, indent=2))

