    ord_match = re.search(r'"Ordinal":\s*(\d+)', vi)
    rel_match = re.search(r'"IsRelease":\s*(true|false)', vi)

    if ord_match and rel_match:
        ordinal = int(ord_match.group(1))
        is_rel = rel_match.group(1) == 'true'

        if is_rel:
